//------------------------------------------------------------------------------
// Callback Name: update_cb
//------------------------------------------------------------------------------
int setholecolor::update_cb(NXOpen::BlockStyler::UIBlock* block)
{
	try
	{
		Part* workPart = theSession->Parts()->Work();
		Part* displayPart = theSession->Parts()->Display();
		ListingWindow* lw = theSession->ListingWindow();
		lw->Open();

		if (workPart == NULL && displayPart == NULL)
		{
			theUI->NXMessageBox()->Show(
				"戻幣",
				NXOpen::NXMessageBox::DialogTypeWarning,
				"輝念短嗤嬉蝕議垢恬何周賜𠮟幣何周。");
			return 0;
		}

		if (block == toggle0)
		{
			if (toggle0->Value())
			{
				ClearHighlight();

				DiagnoseInfo workInfo;
				DiagnoseInfo displayInfo;
				std::vector<NXOpen::DisplayableObject*> workFaces;
				std::vector<NXOpen::DisplayableObject*> displayFaces;

				if (workPart != NULL)
					DiagnoseAndFindHoleFaces(workPart, workFaces, workInfo, lw);

				if (displayPart != NULL)
				{
					if (displayPart != workPart)
						DiagnoseAndFindHoleFaces(displayPart, displayFaces, displayInfo, lw);
					else
						displayInfo = workInfo;
				}

				bool useDisplayPart = false;

				// 單枠喘 workPart◉泌惚 workPart 短鎮欺 body⇧遇 displayPart 鎮欺阻⇧夸指曜欺 displayPart
				if (workInfo.totalBodies > 0 || workInfo.solidBodies > 0)
				{
					g_holeFaces = workFaces;
					useDisplayPart = false;
				}
				else if (displayInfo.totalBodies > 0 || displayInfo.solidBodies > 0)
				{
					g_holeFaces = displayFaces;
					useDisplayPart = true;
				}
				else
				{
					g_holeFaces.clear();
				}

				HighlightFaces(g_holeFaces);

				std::ostringstream oss;
				oss << "寶僅頼撹。\n\n";

				if (workPart != NULL)
				{
					oss << "[Work Part] " << workInfo.partName << "\n"
						<< "Body悳方: " << workInfo.totalBodies << "\n"
						<< "糞悶Body方: " << workInfo.solidBodies << "\n"
						<< "悳中方: " << workInfo.totalFaces << "\n"
						<< "峠中方: " << workInfo.planarFaces << "\n"
						<< "垈庠中方: " << workInfo.cylindricalFaces << "\n"
						<< "垈弑中方: " << workInfo.conicalFaces << "\n"
						<< "凪麿中方: " << workInfo.otherFaces << "\n"
						<< "夘貌迅中方: " << workInfo.candidateHoleFaces << "\n\n";
				}

				if (displayPart != NULL)
				{
					oss << "[Display Part] " << displayInfo.partName << "\n"
						<< "Body悳方: " << displayInfo.totalBodies << "\n"
						<< "糞悶Body方: " << displayInfo.solidBodies << "\n"
						<< "悳中方: " << displayInfo.totalFaces << "\n"
						<< "峠中方: " << displayInfo.planarFaces << "\n"
						<< "垈庠中方: " << displayInfo.cylindricalFaces << "\n"
						<< "垈弑中方: " << displayInfo.conicalFaces << "\n"
						<< "凪麿中方: " << displayInfo.otherFaces << "\n"
						<< "夘貌迅中方: " << displayInfo.candidateHoleFaces << "\n\n";
				}

				if (useDisplayPart)
					oss << "云肝互疏聞喘議頁 Display Part 議膝宙潤惚。";
				else
					oss << "云肝互疏聞喘議頁 Work Part 議膝宙潤惚。";

				theUI->NXMessageBox()->Show(
					"庁侏/迅紛艶寶僅潤惚",
					NXOpen::NXMessageBox::DialogTypeInformation,
					oss.str().c_str());

				toggle0->SetValue(false);
			}
		}
		else if (block == toggle01)
		{
			if (toggle01->Value())
			{
				if (g_holeFaces.empty())
				{
					DiagnoseInfo workInfo;
					DiagnoseInfo displayInfo;
					std::vector<NXOpen::DisplayableObject*> workFaces;
					std::vector<NXOpen::DisplayableObject*> displayFaces;

					if (workPart != NULL)
						DiagnoseAndFindHoleFaces(workPart, workFaces, workInfo, lw);

					if (displayPart != NULL)
					{
						if (displayPart != workPart)
							DiagnoseAndFindHoleFaces(displayPart, displayFaces, displayInfo, lw);
						else
							displayInfo = workInfo;
					}

					if (workInfo.totalBodies > 0 || workInfo.solidBodies > 0)
						g_holeFaces = workFaces;
					else
						g_holeFaces = displayFaces;

					HighlightFaces(g_holeFaces);
				}

				if (g_holeFaces.empty())
				{
					theUI->NXMessageBox()->Show(
						"戻幣",
						NXOpen::NXMessageBox::DialogTypeWarning,
						"輝念短嗤辛炎碕議夘貌迅中。萩枠泣及匯倖梓泥臥心寶僅潤惚。");
				}
				else
				{
					ColorFacesRed(g_holeFaces);

					std::ostringstream oss;
					oss << "炎碕頼撹。\n"
						<< "厮炎碕迅中方楚: " << g_holeFaces.size();

					theUI->NXMessageBox()->Show(
						"迅彭弼潤惚",
						NXOpen::NXMessageBox::DialogTypeInformation,
						oss.str().c_str());
				}

				toggle01->SetValue(false);
			}
		}
	}
	catch (exception& ex)
	{
		setholecolor::theUI->NXMessageBox()->Show(
			"Block Styler",
			NXOpen::NXMessageBox::DialogTypeError,
			ex.what());
	}
	return 0;
}


